<?phpnamespace App\Controller;use App\Entity\BienClient;use App\Entity\ClientStructure;use App\Entity\Commune;use App\Entity\DocumentExpertise;use App\Entity\DocumentImage;use App\Entity\DocumentPdf;use App\Entity\DossierMbeyan;use App\Entity\Expertise;use App\Entity\OtherDocument;use App\Entity\Quartier;use App\Entity\SysAdminOperation;use App\Entity\TypeCompte;use App\Form\BienClientType;use App\Helpers\BienClientHelper;use App\Repository\BienClientRepository;use App\Repository\CercleRepository;use App\Repository\ClientStructureRepository;use App\Repository\CommuneRepository;use App\Repository\DossierMbeyanRepository;use App\Repository\ExpertiseRepository;use App\Repository\KohUtilisateurRepository;use App\Repository\QuartierRepository;use App\Repository\RegionRepository;use App\Repository\TypeAcquisitionRepository;use App\Repository\TypeBienRepository;use App\Repository\TypeCompteRepository;use App\Repository\TypeDocumentProprieteRepository;use App\Repository\TypeUsageBienRepository;use DateTime;use DateTimeImmutable;use DateTimeZone;use Exception;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\File\File;use Symfony\Component\HttpFoundation\File\UploadedFile;use Symfony\Component\HttpFoundation\JsonResponse;use Symfony\Component\HttpFoundation\RedirectResponse;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\RequestStack;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;use Symfony\Component\Validator\Constraints\Date;class BienClientController extends AbstractController{    /**     * @var string     */    protected $baseUrl;    /**     * @var BienClientHelper     */    private $bienClientHelper;    /**     * @param RequestStack $requestStack     * @param BienClientHelper $bienClientHelper     */    public function __construct(RequestStack $requestStack, BienClientHelper $bienClientHelper)    {        $this->baseUrl = $requestStack->getCurrentRequest()->getSchemeAndHttpHost();        $this->bienClientHelper = $bienClientHelper;    }    /**     * LA PAGE INDEX POUR LA LISTE DES EXPERTISES DES BIENS DES CLIENTS     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/bien-clients", name="bien_client_index", methods={"GET", "POST"})     * @param TypeCompteRepository $typeCompteRepository     * @param TypeDocumentProprieteRepository $typeDocumentProprieteRepository     * @param TypeAcquisitionRepository $typeAcquisitionRepository     * @param TypeUsageBienRepository $typeUsageBienRepository     * @param TypeBienRepository $typeBienRepository     * @param RegionRepository $regionRepository     * @param CercleRepository $cercleRepository     * @param QuartierRepository $quartierRepository     * @return Response     */    public function index(TypeCompteRepository $typeCompteRepository, TypeDocumentProprieteRepository $typeDocumentProprieteRepository, TypeAcquisitionRepository $typeAcquisitionRepository, TypeUsageBienRepository $typeUsageBienRepository, TypeBienRepository $typeBienRepository, RegionRepository $regionRepository, CercleRepository $cercleRepository, QuartierRepository $quartierRepository): ?Response    {        return $this->render('bien_client/index.html.twig', [            'typeComptes' => $typeCompteRepository->findAll(),            'typeDocuments' => $typeDocumentProprieteRepository->findAll(),            'typeAcquisitions' => $typeAcquisitionRepository->findAll(),            'typeUsageBiens' => $typeUsageBienRepository->findAll(),            'typeBiens' => $typeBienRepository->findAll(),            'regions' => $regionRepository->findAll(),            'cercles' => $cercleRepository->findAll(),            'quartiers' => $quartierRepository->findAll()        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/bien-clients/new", name="bien_client_new", methods={"GET", "POST"})     * @param CommuneRepository $communeRepository     * @param ClientStructureRepository $clientStructureRepository     * @param DossierMbeyanRepository $dossierMbeyanRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @param CercleRepository $cercleRepository     * @param QuartierRepository $quartierRepository     * @param BienClientRepository $bienClientRepository     * @param TypeCompteRepository $typeCompteRepository     * @param TypeBienRepository $typeBienRepository     * @param TypeDocumentProprieteRepository $typeDocumentProprieteRepository     * @param Request $request     * @param TypeAcquisitionRepository $typeAcquisitionRepository     * @param TypeUsageBienRepository $typeUsageBienRepository     * @return Response     * @throws Exception     */    public function new(CommuneRepository $communeRepository, ClientStructureRepository $clientStructureRepository, DossierMbeyanRepository $dossierMbeyanRepository, KohUtilisateurRepository $kohUtilisateurRepository, CercleRepository $cercleRepository, QuartierRepository $quartierRepository, BienClientRepository $bienClientRepository, TypeCompteRepository $typeCompteRepository, TypeBienRepository $typeBienRepository, TypeDocumentProprieteRepository $typeDocumentProprieteRepository, Request $request, TypeAcquisitionRepository $typeAcquisitionRepository, TypeUsageBienRepository $typeUsageBienRepository): Response    {        $newBien = new BienClient();        $formAdd = $this->createForm(BienClientType::class, $newBien);        $formAdd->handleRequest($request);        if ($formAdd->isSubmitted() && $formAdd->isValid()) {            $em = $this->getDoctrine()->getManager();            $bienData = $request->get('bien_client');            $typeAcquisition = $typeAcquisitionRepository->find($bienData['typeAcquisition']);            $typeUsageBien = $typeUsageBienRepository->find($bienData['typeUsageBien']);            $typeDocument = $typeDocumentProprieteRepository->find($bienData['typeDocument']);            $typeBien = $typeBienRepository->find($bienData['typeBien']);            $numeroDocument = $bienData['numeroDocument'];            $ninacad = $bienData['ninacad'];            $typeCompte = $typeCompteRepository->find($bienData['typeCompte']);            $cercle = $cercleRepository->find($request->get('cercle'));            $quartierName = $request->get('bien_quartier');            $numeroExpertise = $request->get('numero_expertise');            $numeroDossier = $request->get('numero_dossier');            $superficie = floatval(str_replace(',', '', $request->get('superifie')));            $latitude = $request->get('latitude');            $longitude = $request->get('longitude');            $lastEvaluationPrice = floatval(str_replace(',', '', $request->get('lastEvaluationPrice')));            $lastEvaluationDate = new DateTimeImmutable($request->get('last_evaluation_date'));            $nextEvaluationDate = new DateTimeImmutable($request->get('next_evaluation_date'));            $prenomProprietaire = $request->get('prenomProprietaire');            $volumeFoncier = $request->get('volume_foncier');            $foncierF = $request->get('foncier_f');            $kohClientId = $request->get('client_koh');            $nomClientStructure = $request->get('nom_client_banque');            $numeroCompteClientBanque = $request->get('numero_client_banque');            $contactClientBanque = $request->get('contact_client_banque');            $adresseClientBanque = $request->get('adresse_client_banque');            $dateFinDation = new DateTimeImmutable($request->get('date_fin_dation'));            $dateSortiImmobilisation = new DateTimeImmutable($request->get('date_sorti_immobilisation'));            $memo = $request->get('memo');            $remarque = $request->get('remarque');            $other = $request->get('other');            $dateEntree = new DateTimeImmutable($request->get('date_entree'));            $montantAcquisition = floatval(str_replace(',', '', $request->get('montant_acquisition')));            $fraisAcquisition = floatval(str_replace(',', '', $request->get('frais_acquisition')));            $isFounded = false;            // RECHERCHE DU QUARTIER            $lastQuartiers = $quartierRepository->findQuartierByName($quartierName);            $kohUtilisateur = $kohUtilisateurRepository->find($kohClientId);            $lastBien = null;            $newExpertise = new Expertise();            foreach ($lastQuartiers as $lastQuartier) {                // RECHERCHE D'ANCIEN ENREGISTREMENT DU BIEN AVEC NUMERO, QUARTIER                $lastBien = $bienClientRepository->findOneBy(['numeroDocument' => $numeroDocument, 'Quartier' => $lastQuartier, 'kohUtilisateur' => $kohUtilisateur]);                if ($lastBien != null) {                    $isFounded = true;                    $newQuartier = $lastQuartier;                    break;                }            }            if (!$isFounded) {                $newQuartier = $quartierRepository->findOneBy(['name' => $quartierName]);                if ($newQuartier == null) {                    $newQuartier = new Quartier();                    $commune = $communeRepository->findOneBy(['name' => $cercle->getName()]);                    if ($commune == null) {                        $commune = new Commune();                        $commune->setName($cercle->getName())                            ->setCercle($cercle)                            ->setLatitude($cercle->getLatitude())                            ->setLongitude($cercle->getLongitude());                        $em->persist($commune);                    }                    $newQuartier->setName($quartierName)                        ->setLatitude($latitude)                        ->setLongitude($longitude)                        ->setCommune($commune);                    $em->persist($newQuartier);                }                $newBien = new BienClient();                $newBien->setCreatedAt(new DateTimeImmutable())                    ->setKohUtilisateur($kohUtilisateur)                    ->setNinacad($ninacad)                    ->setNumeroDocument($numeroDocument)                    ->setQuartier($newQuartier)                    ->setUpdatedAt(new DateTimeImmutable());                if ($typeCompte->getIsStructure()) {                    $newBien->setIsForStructure(true);                } else {                    $newBien->setIsForStructure(false);                }                $em->persist($newBien);                $newExpertise->setBienClient($newBien);            } else {                $newBien = $lastBien;                $newBien->setUpdatedAt(new DateTimeImmutable())                    ->setNinacad($ninacad);                $newExpertise->setBienClient($lastBien);            }            $newExpertise->setLongitude($latitude)                ->setLongitude($longitude)                ->setLatitude($latitude)                ->setLastEvaluationPrice($lastEvaluationPrice)                ->setSuperficie($superficie)                ->setNumeroExpertise($numeroExpertise)                ->setCreatedAt(new DateTimeImmutable())                ->setUpdatedAt(new DateTimeImmutable())                ->setBienClient($newBien)                ->setCreatedBy($this->getUser())                ->setDateEntree($dateEntree)                ->setDateEvaluation($lastEvaluationDate)                ->setDateFinDation($dateFinDation)                ->setDateNextEvaluation($nextEvaluationDate)                ->setDateSortieImmobilisation($dateSortiImmobilisation)                ->setFoncierF($foncierF)                ->setVolumeFoncier($volumeFoncier)                ->setFraisAcquisition($fraisAcquisition)                ->setMontantAcquisition($montantAcquisition)                ->setInfoProprietaire($prenomProprietaire)                ->setMemo($memo)                ->setRemarque($remarque)                ->setOther($other)                ->setTypeAcquisition($typeAcquisition)                ->setTypeBien($typeBien)                ->setTypeDocumentPropriete($typeDocument)                ->setTypeUsageBien($typeUsageBien);            // TODO REPLACE CODE            $file = $request->files->get('iconImage');            if ($file) {                // $fileF = new UploadedFile($file['tmp_name'], $file['name']);                // $newExpertise->setBienIcon($fileF);                $newExpertise->setBienIcon($file);            }            $lastDossier = $dossierMbeyanRepository->findOneBy(['numeroDossier' => $numeroDossier]);            if ($lastDossier == null) {                $dossierMbeyan = new DossierMbeyan();                $dossierMbeyan->setCreatedAt(new DateTimeImmutable())                    ->setUpdatedAt(new DateTimeImmutable())                    ->setNumeroDossier($numeroDossier);                $em->persist($dossierMbeyan);                $newExpertise->setDossierMbeyan($dossierMbeyan);            } else {                $newExpertise->setDossierMbeyan($lastDossier);            }            if ($typeCompte->getIsStructure()) {                $newExpertise->setIsForStructure(true);                $lastClientStructure = null;                if ($numeroCompteClientBanque != null) {                    $lastClientStructure = $clientStructureRepository->findOneBy(['numero_compte' => $numeroCompteClientBanque]);                }                if ($lastClientStructure === null) {                    $clientStructure = new ClientStructure();                    $clientStructure->setName($nomClientStructure)                        ->setAdresse($adresseClientBanque)                        ->setNumeroCompte($numeroCompteClientBanque)                        ->setTel($contactClientBanque)                        ->setStructure($kohUtilisateur->getStructure());                    $em->persist($clientStructure);                    $newExpertise->setClientStructure($clientStructure);                } else {                    $newExpertise->setClientStructure($lastClientStructure);                }            } else {                $newBien->setIsForStructure(false);            }            $em->persist($newExpertise);            $em->flush();            $this->addFlash('success', 'Le bien client a été enregistré');            return $this->redirectToRoute('bien_client_index');        }        return $this->render('bien_client/add.html.twig', [            'form' => $formAdd->createView()        ]);    }    /**     * LA PAGE EDIT POUR LA MODIFICATION D'UNE EXPERTISE     * @param BienClientRepository $bienClientRepository     * @param Expertise $expertise     * @param Request $request     * @param DossierMbeyanRepository $dossierMbeyanRepository     * @param QuartierRepository $quartierRepository     * @param TypeCompteRepository $typeCompteRepository     * @param ClientStructureRepository $clientStructureRepository     * @param TypeAcquisitionRepository $acquisitionRepository     * @param TypeUsageBienRepository $typeUsageBienRepository     * @param TypeDocumentProprieteRepository $typeDocumentProprieteRepository     * @param TypeBienRepository $typeBienRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @param TypeCompteRepository $compteRepository     * @param RegionRepository $regionRepository     * @return Response     * @throws Exception     */    public function edit(BienClientRepository $bienClientRepository, Expertise $expertise, Request $request, DossierMbeyanRepository $dossierMbeyanRepository, QuartierRepository $quartierRepository, TypeCompteRepository $typeCompteRepository, ClientStructureRepository $clientStructureRepository, TypeAcquisitionRepository $acquisitionRepository, TypeUsageBienRepository $typeUsageBienRepository, TypeDocumentProprieteRepository $typeDocumentProprieteRepository, TypeBienRepository $typeBienRepository, KohUtilisateurRepository $kohUtilisateurRepository, TypeCompteRepository $compteRepository, RegionRepository $regionRepository): Response    {        // dd($expertise);        $bien = $bienClientRepository->findOneBy(['id' => $expertise->getBienClient()->getId()]);        // dd($bien->getQuartier());        if ($bien === null) {            $this->addFlash('danger', 'Le bien est null');        }        $bien->setLastExpertise($expertise);        $typeAcquisitions = $acquisitionRepository->findAll();        $typeUsages = $typeUsageBienRepository->findAll();        $typeDocuments = $typeDocumentProprieteRepository->findAll();        $typeBiens = $typeBienRepository->findAll();        $regions = $regionRepository->findAll();        $typeComptes = $typeCompteRepository->findAll();        if ($_SERVER['REQUEST_METHOD'] === 'POST') {            $array = $request->get('bien_client');            $manager = $this->getDoctrine()->getManager();            // VERIFICATION QUARTIER            $quartier = $quartierRepository->findOneBy(['name' => $request->get('bien_quartier')]);            if ($quartier === null) {                $quartier = new Quartier();                $quartier->setName($request->get('bien_quartier'))                    ->setLatitude($request->get('quartier_latitude'))                    ->setLongitude($request->get('quartier_longitude'));                $manager->persist($quartier);                $manager->flush();            }            $bien->setQuartier($quartier);            // ENREGISTREMENT KOH USER ASSOCIE AU BIEN            $kohUser = $kohUtilisateurRepository->findOneBy(['id' => $request->get('client_koh')]);            if ($kohUser === null) {                $this->addFlash('danger', 'Le client est null');            }            $bien->setKohUtilisateur($kohUser);            $bien->setNumeroDocument($array['numeroDocument']);            $bien->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));            $bien->setNinacad($array['ninacad']);            $bien->setIsForStructure(false);            if ($kohUser->getTypeCompte()->getIsStructure()) {                $bien->setIsForStructure(true);            }            // VERIFICATION EXPERTISE            $expertise->setNumeroExpertise($request->get('numero_expertise'));            // dd($expertise);            $typeCompte = $this->addExpertiseInfos($expertise, $acquisitionRepository, $array, $typeBienRepository, $typeUsageBienRepository, $typeDocumentProprieteRepository, $bien, $compteRepository);            if ($typeCompte === null) {                $this->addFlash('danger', 'Le type de compte est null');            }            if ($typeCompte->getIsStructure()) {                $clientStructure = $clientStructureRepository->findOneBy(['numero_compte' => $request->get('numero_client_banque')]);                if ($clientStructure === null) {                    $clientStructure = new ClientStructure();                    $clientStructure->setNumeroCompte($request->get('numero_client_banque'))                        ->setName($request->get('nom_client_banque'))                        ->setAdresse($request->get('adresse_client_banque'))                        ->setStructure($kohUser->getStructure())                        ->setTel($request->get('contact_client_banque'));                    $manager->persist($clientStructure);                }                $expertise->setClientStructure($clientStructure);                $expertise->setIsForStructure(true);            }            // ENREGISTREMENT DOSSIER            $dossier = $dossierMbeyanRepository->findOneBy(['numeroDossier' => $request->get('numero_dossier')]);            if ($dossier === null) {                $dossier = new DossierMbeyan();                $dossier->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                    ->setNumeroDossier($request->get('numero_dossier'));                $manager->persist($dossier);            } else {                $dossier->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));            }            $expertise->setDossierMbeyan($dossier);            // ENREGISTREMENT CLIENT STRUCTURE            if ($typeCompte->getIsStructure()) {                $clientStructure = $clientStructureRepository->findOneBy(['numero_compte' => $request->get('numero_client_banque')]);                if ($clientStructure === null) {                    $clientStructure = new ClientStructure();                    $clientStructure->setNumeroCompte($request->get('numero_client_banque'))                        ->setName($request->get('nom_client_banque'))                        ->setAdresse($request->get('adresse_client_banque'))                        ->setStructure($kohUser->getStructure())                        ->setTel($request->get('contact_client_banque'));                    $manager->persist($clientStructure);                } else {                    $clientStructure->setNumeroCompte($request->get('numero_client_banque'))                        ->setName($request->get('nom_client_banque'))                        ->setAdresse($request->get('adresse_client_banque'))                        ->setStructure($kohUser->getStructure())                        ->setTel($request->get('contact_client_banque'));                }                $expertise->setClientStructure($clientStructure);                $expertise->setIsForStructure(true);            }            // $expertise->setNumeroExpertise($request->get('numero_expertise'));            $expertise->setLatitude($request->get('latitude'))                ->setBienClient($bien)                ->setLongitude($request->get('longitude'))                ->setDateEvaluation(new DateTime($request->get('last_evaluation_date'), new DateTimeZone('GMT')))                ->setDateNextEvaluation(new DateTime($request->get('next_evaluation_date'), new DateTimeZone('GMT')))                ->setLastEvaluationPrice($request->get('lastEvaluationPrice'))                ->setSuperficie((int)$request->get('superifie'))                ->setMemo($request->get('memo'))                ->setRemarque($request->get('remarque'))                ->setOther($request->get('other'))                ->setInfoProprietaire($request->get('nomProprietaire') . ' ' . $request->get('prenomProprietaire'));            if ($expertise->getTypeAcquisition()->getIsBienForStructure()) {                if ($request->get('date_entree')) {                    $expertise->setDateEntree(new DateTime($request->get('date_entree'), new DateTimeZone('GMT')));                }                $expertise->setMontantAcquisition((int)$request->get('montant_acquisition'));                $expertise->setFraisAcquisition((int)$request->get('frais_acquisition'));            }            if ($request->get('date_sorti_immobilisation')) {                $expertise->setDateSortieImmobilisation(new DateTime($request->get('date_sorti_immobilisation'), new DateTimeZone('GMT')));            }            if ($request->get('date_fin_dation')) {                $expertise->setDateFinDation(new DateTime($request->get('date_fin_dation'), new DateTimeZone('GMT')));            }            $expertise->setFoncierF($request->get('foncier_f'));            $expertise->setVolumeFoncier($request->get('volume_foncier'));            // TODO REPLACE CODE            $file = $request->files->get('iconImage');            // $fileF = new UploadedFile(            // $request->files->get('iconImage')['tmp_name'],            // $request->files->get('iconImage')['name']);            // $expertise->setBienIcon($fileF);            $expertise->setBienIcon($file);            $expertise->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));            // dd($expertise);            $this->bienClientHelper->saveExpertiseFiles($request, $expertise, $manager);            $this->addFlash('success', 'Le bien a été modifié avec succes');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setDescription('Modification du bien numero document ' . $bien->getNumeroDocument())                ->setKohUtilisateur($this->getUser())                ->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));            $manager->persist($sysOp);            $manager->flush();            // dd($expertise);            return $this->redirectToRoute('bien_client_index');        }        return $this->render('bien_client/edit.html.twig', [            'bien' => $bien,            'typeAcquisitions' => $typeAcquisitions,            'typeUsages' => $typeUsages,            'typeDocuments' => $typeDocuments,            'typeBiens' => $typeBiens,            'typeComptes' => $typeComptes,            'regions' => $regions,        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/bien-clients/{id}/edit", name="bien_client_edit", methods={"GET", "POST"})     * @param ClientStructureRepository $clientStructureRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @param DossierMbeyanRepository $dossierMbeyanRepository     * @param QuartierRepository $quartierRepository     * @param CommuneRepository $communeRepository     * @param CercleRepository $cercleRepository     * @param Request $request     * @param TypeUsageBienRepository $typeUsageBienRepository     * @param RegionRepository $regionRepository     * @param TypeCompteRepository $typeCompteRepository     * @param TypeAcquisitionRepository $typeAcquisitionRepository     * @param TypeDocumentProprieteRepository $typeDocumentProprieteRepository     * @param TypeBienRepository $typeBienRepository     * @param Expertise $expertise     * @param BienClientRepository $bienClientRepository     * @return Response     * @throws Exception     */    public function editBienClient(ClientStructureRepository $clientStructureRepository, KohUtilisateurRepository $kohUtilisateurRepository, DossierMbeyanRepository $dossierMbeyanRepository, QuartierRepository $quartierRepository, CommuneRepository $communeRepository, CercleRepository $cercleRepository, Request $request, TypeUsageBienRepository $typeUsageBienRepository, RegionRepository $regionRepository, TypeCompteRepository $typeCompteRepository, TypeAcquisitionRepository $typeAcquisitionRepository, TypeDocumentProprieteRepository $typeDocumentProprieteRepository, TypeBienRepository $typeBienRepository, Expertise $expertise, BienClientRepository $bienClientRepository): Response    {        $bienEdit = $expertise->getBienClient();        $bienEdit->setLastExpertise($bienEdit->getExpertises()->last());        if ($_SERVER['REQUEST_METHOD'] === 'POST') {            $em = $this->getDoctrine()->getManager();            $bienData = $request->get('bien_client');            $typeAcquisition = $typeAcquisitionRepository->find($bienData['typeAcquisition']);            $typeUsageBien = $typeUsageBienRepository->find($bienData['typeUsageBien']);            $typeDocument = $typeDocumentProprieteRepository->find($bienData['typeDocument']);            $typeBien = $typeBienRepository->find($bienData['typeBien']);            $numeroDocument = $bienData['numeroDocument'];            $ninacad = $bienData['ninacad'];            $typeCompte = $typeCompteRepository->find($bienData['typeCompte']);            $cercle = $cercleRepository->find($request->get('cercle'));            $quartierName = $request->get('bien_quartier');            $numeroExpertise = $request->get('numero_expertise');            $numeroDossier = $request->get('numero_dossier');            $superficie = floatval(str_replace(',', '', $request->get('superifie')));            $latitude = $request->get('latitude');            $longitude = $request->get('longitude');            $lastEvaluationPrice = floatval(str_replace(',', '', $request->get('lastEvaluationPrice')));            $lastEvaluationDate = new DateTimeImmutable($request->get('last_evaluation_date'));            $nextEvaluationDate = new DateTimeImmutable($request->get('next_evaluation_date'));            $prenomProprietaire = $request->get('prenomProprietaire');            $volumeFoncier = $request->get('volume_foncier');            $foncierF = $request->get('foncier_f');            $kohClientId = $request->get('client_koh');            $nomClientStructure = $request->get('nom_client_banque');            $numeroCompteClientBanque = $request->get('numero_client_banque');            $contactClientBanque = $request->get('contact_client_banque');            $adresseClientBanque = $request->get('adresse_client_banque');            $dateFinDation = new DateTimeImmutable($request->get('date_fin_dation'));            $dateSortiImmobilisation = new DateTimeImmutable($request->get('date_sorti_immobilisation'));            $memo = $request->get('memo');            $remarque = $request->get('remarque');            $other = $request->get('other');            $dateEntree = new DateTimeImmutable($request->get('date_entree'));            $montantAcquisition = $request->get('montant_acquisition');            $fraisAcquisition = $request->get('frais_acquisition');            $newQuartier = $quartierRepository->findOneBy(['name' => $quartierName]);            if ($newQuartier == null) {                $newQuartier = new Quartier();                $commune = $communeRepository->findOneBy(['name' => $cercle->getName()]);                if ($commune == null) {                    $commune = new Commune();                    $commune->setName($cercle->getName())                        ->setCercle($cercle)                        ->setLatitude($cercle->getLatitude())                        ->setLongitude($cercle->getLongitude());                    $em->persist($commune);                }                $newQuartier->setName($quartierName)                    ->setLatitude($latitude)                    ->setLongitude($longitude)                    ->setCommune($commune);                $em->persist($newQuartier);            }            $bienEdit->setNinacad($ninacad)                ->setUpdatedAt(new DateTimeImmutable())                ->setNumeroDocument($numeroDocument)                ->setQuartier($newQuartier);            if ($typeCompte->getIsStructure()) {                $bienEdit->setIsForStructure(true);            } else {                $bienEdit->setIsForStructure(false);            }            $kohUtilisateur = $kohUtilisateurRepository->find($kohClientId);            $expertise->setLongitude($latitude)                ->setLongitude($longitude)                ->setLatitude($latitude)                ->setLastEvaluationPrice($lastEvaluationPrice)                ->setSuperficie($superficie)                ->setNumeroExpertise($numeroExpertise)                ->setCreatedAt(new DateTimeImmutable())                ->setUpdatedAt(new DateTimeImmutable())                ->setBienClient($bienEdit)                ->setUpdatedBy($this->getUser())                ->setDateEntree($dateEntree)                ->setDateEvaluation($lastEvaluationDate)                ->setDateFinDation($dateFinDation)                ->setDateNextEvaluation($nextEvaluationDate)                ->setDateSortieImmobilisation($dateSortiImmobilisation)                ->setFoncierF($foncierF)                ->setVolumeFoncier($volumeFoncier)                ->setFraisAcquisition(floatval($fraisAcquisition))                ->setMontantAcquisition(floatval($montantAcquisition))                ->setInfoProprietaire($prenomProprietaire)                ->setMemo($memo)                ->setRemarque($remarque)                ->setOther($other)                ->setTypeAcquisition($typeAcquisition)                ->setTypeBien($typeBien)                ->setTypeDocumentPropriete($typeDocument)                ->setTypeUsageBien($typeUsageBien);            // TODO REPLACE CODE            $file = $request->files->get('iconImage');            // if ($file && $file['tmp_name'] && $file['name']) {            // $fileF = new UploadedFile($file['tmp_name'], $file['name']);            // $expertise->setBienIcon($fileF);            $expertise->setBienIcon($file);            // }            $lastDossier = $dossierMbeyanRepository->findOneBy(['numeroDossier' => $numeroDossier]);            if ($lastDossier == null) {                $dossierMbeyan = new DossierMbeyan();                $dossierMbeyan->setCreatedAt(new DateTimeImmutable())                    ->setUpdatedAt(new DateTimeImmutable())                    ->setNumeroDossier($numeroDossier);                $em->persist($dossierMbeyan);                $expertise->setDossierMbeyan($dossierMbeyan);            } else {                $expertise->setDossierMbeyan($lastDossier);            }            if ($typeCompte->getIsStructure()) {                $expertise->setIsForStructure(true);                $lastClientStructure = $clientStructureRepository->findOneBy(['numero_compte' => $numeroCompteClientBanque]);                if ($lastClientStructure == null) {                    $clientStructure = new ClientStructure();                    $clientStructure->setName($nomClientStructure . ' ' . $prenomProprietaire)                        ->setAdresse($adresseClientBanque)                        ->setNumeroCompte($numeroCompteClientBanque)                        ->setTel($contactClientBanque)                        ->setStructure($kohUtilisateur->getStructure());                    $em->persist($clientStructure);                    $expertise->setClientStructure($clientStructure);                } else {                    $expertise->setClientStructure($lastClientStructure);                }            } else {                $bienEdit->setIsForStructure(false);                $bienEdit->setKohUtilisateur($kohUtilisateur);                $expertise->setIsForStructure(false);                $expertise->setClientStructure(null);            }            $em->flush();            $this->addFlash('success', 'Bien client modifié');            return $this->redirectToRoute('bien_client_index');        }        return $this->render('bien_client/editBienClient.html.twig', [            'bien' => $bienEdit,            'regions' => $regionRepository->findAll(),            'typeAcquisitions' => $typeAcquisitionRepository->findAll(),            'typeDocuments' => $typeDocumentProprieteRepository->findAll(),            'typeBiens' => $typeBienRepository->findAll(),            'typeUsages' => $typeUsageBienRepository->findAll(),            'typeComptes' => $typeCompteRepository->findAll()        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/bien-clients/detail-bien/{id}", methods={"GET"}, name="super_admin.bien_client_detail")     * @param Expertise $expertise     * @return Response     */    public function show(Expertise $expertise): ?Response    {        $bienClient = $expertise->getBienClient();        if ($bienClient === null) {            $this->addFlash('danger', 'Le bien client est null');        }        $bienClient->setLastExpertise($expertise);        return $this->render('bien_client/bien_mbeyan_detail.html.twig', [            'bien' => $bienClient        ]);    }    /**     * LA PAGE DELETE POUR LA SUPPRESSION D'UNE EXPERTISE     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/bien-clients/delete/{id}", name="super_admin.delete_bienclient", methods={"GET","DELETE"})     * @param Request $request     * @param Expertise $expertise     * @return RedirectResponse     * @throws Exception     */    public function delete(Request $request, Expertise $expertise): RedirectResponse    {        if ($this->isCsrfTokenValid('delete' . $expertise->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $bienClient = $expertise->getBienClient();            if ($bienClient === null) {                $this->addFlash('danger', 'Le bien client est null');            }            $bienClient->setLastExpertise($expertise);            $lastExpertise = $bienClient->getLastExpertise();            $entityManager->remove($lastExpertise);            $entityManager->flush();            $this->addFlash('success', 'L\'expertise a été supprimé !');            if ($bienClient->getExpertises() === []) {                $entityManager->remove($bienClient);                $entityManager->flush();            }            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setDescription('Suppression du bien numero document ')                ->setUserAffected($bienClient->getNumeroDocument() . ' à ' . $bienClient->getQuartier()->getName())                ->setKohUtilisateur($this->getUser())                ->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));            $entityManager->persist($sysOp);            $entityManager->flush();        }        return $this->redirectToRoute('bien_client_index');    }    /**     * LA PAGE MAP DES BIENS DES CLIENTS     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/bien-clients/bien-mbeyan-sur-map", name="super_admin.bien_mbeyan_sur_map")     * @param TypeUsageBienRepository $typeUsageBienRepository     * @param TypeBienRepository $typeBienRepository     * @param TypeCompteRepository $typeCompteRepository     * @param TypeDocumentProprieteRepository $typeDocumentProprieteRepository     * @param TypeAcquisitionRepository $typeAcquisitionRepository     * @param RegionRepository $regionRepository     * @param CercleRepository $cercleRepository     * @param QuartierRepository $quartierRepository     * @return Response     */    public function mapBiens(TypeUsageBienRepository $typeUsageBienRepository, TypeBienRepository $typeBienRepository, TypeCompteRepository $typeCompteRepository, TypeDocumentProprieteRepository $typeDocumentProprieteRepository, TypeAcquisitionRepository $typeAcquisitionRepository, RegionRepository $regionRepository, CercleRepository $cercleRepository, QuartierRepository $quartierRepository): ?Response    {        return $this->render('bien_client/all_bien_sur_map.html.twig', [            'typeComptes' => $typeCompteRepository->findAll(),            'typeDocuments' => $typeDocumentProprieteRepository->findAll(),            'typeAcquisitions' => $typeAcquisitionRepository->findAll(),            'typeUsageBiens' => $typeUsageBienRepository->findAll(),            'typeBiens' => $typeBienRepository->findAll(),            'regions' => $regionRepository->findAll(),            'cercles' => $cercleRepository->findAll(),            'quartiers' => $quartierRepository->findAll()        ]);    }    /**     * DATA JSON DES EXPERTISES POUR INDEX     * @Route("/get-all-expertises", methods={"GET"})     * @param Request $request     * @param ExpertiseRepository $expertiseRepository     * @return JsonResponse     */    public function jsonDataForIndex(Request $request, ExpertiseRepository $expertiseRepository): JsonResponse    {        $expertises = $this->bienClientHelper->getExpertiseSorted($request, $expertiseRepository);        return new JsonResponse($this->bienClientHelper->serialiseExpertises($expertises, $this->baseUrl), 200);    }    /**     * DATA JSON DE TOUS LES BIENS POUR LE MAP     * @Route("/koh_biens/biens-client/get_biens")     * @param BienClientRepository $bienClientRepository     * @return JsonResponse     */    public function jsonDataForMap(BienClientRepository $bienClientRepository): JsonResponse    {        $biens = $bienClientRepository->findAll();        $this->bienClientHelper->getLastExpertise($biens);        return new JsonResponse($this->bienClientHelper->serializeBiens($biens, $this->baseUrl), 200);    }    /**     * DATA JSON DU BIEN POUR LE DETAIL MAP     * @Route("/koh-archivage/bien-client/{id}/get", methods={"GET"})     * @param int $id     * @param ExpertiseRepository $expertiseRepository     * @return JsonResponse     */    public function jsonBienByIdForDetail(int $id, ExpertiseRepository $expertiseRepository): JsonResponse    {        $expertise = $expertiseRepository->findOneBy(['id' => $id]);        if ($expertise === null) {            $this->addFlash('danger', 'L\'expertise est nulle');        }        $bienClient = $expertise->getBienClient();        if ($bienClient === null) {            $this->addFlash('danger', 'Le bien client est null');        }        $bienClient->setLastExpertise($expertise);        return new JsonResponse($this->bienClientHelper->serializeBien($bienClient, $this->baseUrl), 200);    }    /**     * DATA JSON DES BIENS CLIENTS SELECTIONNES DANS INDEX ET MAP     * @Route("/koh-archivage/biens-by-array/{data}/order/{by}/type/{sortType}", methods={"GET"})     * @param String $data     * @param string $by     * @param string $sortType     * @param ExpertiseRepository $expertiseRepository     * @return JsonResponse     */    public function jsonDataForSelectedExpertises(string $data, string $by, string $sortType, ExpertiseRepository $expertiseRepository): JsonResponse    {        $expertises = $expertiseRepository->getBienClientsByArrayId($data, $by, $sortType);        $bienClients = [];        foreach ($expertises as $expertise) {            $bienClient = $expertise->getBienClient();            $bienClient->setLastExpertise($expertise);            $bienClients[] = $bienClient;        }        return new JsonResponse($this->bienClientHelper->serializeBiens($bienClients, $this->baseUrl), 200);    }    /**     * DATA JSON DES BIENS SELON LES CRITERES POUR INDEX     * @Route("/koh-archivage/get-expertises-by-critere", methods={"POST"})     * @param Request $request     * @param ExpertiseRepository $expertiseRepository     * @return JsonResponse     */    public function jsonDataByCritereForIndex(Request $request, ExpertiseRepository $expertiseRepository): JsonResponse    {        $parameters = $request->request->all();        $expertises = [];        if ($parameters !== []) {            $expertises = $expertiseRepository->getExpertiseByCritere($parameters);        }        return new JsonResponse($this->bienClientHelper->serialiseExpertises($expertises, $this->baseUrl));    }    /**     * @Route("/koh-archivage/get-biens-by-critere", methods={"POST"})     * @param Request $request     * @param BienClientRepository $bienClientRepository     * @return JsonResponse     */    public function jsonDataByCritereForMap(Request $request, BienClientRepository $bienClientRepository): JsonResponse    {        $parameters = $request->request->all();        // return new JsonResponse($parameters);        $biens = [];        if ($parameters !== []) {            $biens = $bienClientRepository->getBienByCritere($parameters);            $this->bienClientHelper->getLastExpertise($biens);        }        return new JsonResponse($this->bienClientHelper->serializeBiens($biens, $this->baseUrl));    }    /**     * @param Expertise $expertise     * @param TypeAcquisitionRepository $acquisitionRepository     * @param $array     * @param TypeBienRepository $typeBienRepository     * @param TypeUsageBienRepository $typeUsageBienRepository     * @param TypeDocumentProprieteRepository $typeDocumentProprieteRepository     * @param BienClient $bienClient     * @param TypeCompteRepository $compteRepository     * @return TypeCompte|null     */    public function addExpertiseInfos(Expertise $expertise, TypeAcquisitionRepository $acquisitionRepository, $array, TypeBienRepository $typeBienRepository, TypeUsageBienRepository $typeUsageBienRepository, TypeDocumentProprieteRepository $typeDocumentProprieteRepository, BienClient $bienClient, TypeCompteRepository $compteRepository): ?TypeCompte    {        $expertise->setTypeAcquisition($acquisitionRepository->find($array['typeAcquisition']));        $expertise->setTypeBien($typeBienRepository->find($array['typeBien']));        $expertise->setTypeUsageBien($typeUsageBienRepository->find($array['typeUsageBien']));        $expertise->setTypeDocumentPropriete($typeDocumentProprieteRepository->find($array['typeDocument']));        $expertise->setBienClient($bienClient);        $typeCompte = $compteRepository->findOneBy(['id' => $array['typeCompte']]);        $expertise->setIsForStructure(false);        return $typeCompte;    }    /**     * @Route("/super-admin/bien-clients/new/{id}/add-file", methods={"POST"}, name="bien_client_new_add_files")     * @param Expertise $expertise     * @param Request $request     * @return RedirectResponse     * @throws Exception     */    public function saveExpertiseFiles(Expertise $expertise, Request $request): RedirectResponse    {        $em = $this->getDoctrine()->getManager();        $this->bienClientHelper->saveExpertiseFiles($request, $expertise, $em);        $this->addFlash('success', 'Les fichiers ont été enregistrés !');        return $this->redirectToRoute('super_admin.bien_client_detail', ['id' => $expertise->getId()]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/bien-clients/delete/{id}/image-document", methods={"DELETE"}, name="bien_client_delete_document_image")     * @param Request $request     * @param DocumentImage $documentImage     * @return RedirectResponse     */    public function deleteExpertiseDocumentImage(Request $request, DocumentImage $documentImage): RedirectResponse    {        $expertise = $documentImage->getExpertise();        if ($this->isCsrfTokenValid('delete' . $documentImage->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->remove($documentImage);            $this->addFlash('success', 'Le document image a été supprimé');            $entityManager->flush();            return $this->redirectToRoute('super_admin.bien_client_detail', ['id' => $expertise->getId()]);        }        return $this->redirectToRoute('super_admin.bien_client_detail', ['id' => $expertise->getId()]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/bien-clients/delete/{id}/expertise-document", methods={"DELETE"}, name="bien_client_delete_document_expertise")     * @param Request $request     * @param DocumentExpertise $documentExpertise     * @return RedirectResponse     */    public function deleteExpertiseDocumentExpertise(Request $request, DocumentExpertise $documentExpertise): RedirectResponse    {        $expertise = $documentExpertise->getExpertise();        if ($this->isCsrfTokenValid('delete' . $documentExpertise->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->remove($documentExpertise);            $this->addFlash('success', 'Le document expertise a été supprimé');            $entityManager->flush();            return $this->redirectToRoute('super_admin.bien_client_detail', ['id' => $expertise->getId()]);        }        return $this->redirectToRoute('super_admin.bien_client_detail', ['id' => $expertise->getId()]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/bien-clients/delete/{id}/pdf-document", methods={"DELETE"}, name="bien_client_delete_document_pdf")     * @param Request $request     * @param DocumentPdf $documentPdf     * @return RedirectResponse     */    public function deleteExpertiseDocumentPdf(Request $request, DocumentPdf $documentPdf): RedirectResponse    {        $expertise = $documentPdf->getExpertise();        if ($this->isCsrfTokenValid('delete' . $documentPdf->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->remove($documentPdf);            $this->addFlash('success', 'Le document pdf a été supprimé');            $entityManager->flush();            return $this->redirectToRoute('super_admin.bien_client_detail', ['id' => $expertise->getId()]);        }        return $this->redirectToRoute('super_admin.bien_client_detail', ['id' => $expertise->getId()]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/bien-clients/delete/{id}/other-document", methods={"DELETE"}, name="bien_client_delete_other_document")     * @param Request $request     * @param OtherDocument $otherDocument     * @return RedirectResponse     */    public function deleteExpertiseDocumentOther(Request $request, OtherDocument $otherDocument): RedirectResponse    {        $expertise = $otherDocument->getExpertise();        if ($this->isCsrfTokenValid('delete' . $otherDocument->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->remove($otherDocument);            $this->addFlash('success', 'Le document autre a été supprimé');            $entityManager->flush();            return $this->redirectToRoute('super_admin.bien_client_detail', ['id' => $expertise->getId()]);        }        return $this->redirectToRoute('super_admin.bien_client_detail', ['id' => $expertise->getId()]);    }}